// 自訂網站編輯器
// 區塊照 HTML flow 排列，不自由拖移；區塊內元件可自由拖移/縮放。
// v11 修正：只有邊框上方「移動」把手可拖曳，雙擊文字可編輯。

const sitePage = document.getElementById('sitePage');

let selectedBlock = null;
let selectedElement = null;
let copiedHTML = null;
let copiedKind = null;
let copiedCarouselSlideHTML = null;
let selectedElements = [];
let lastUsedBlockId = null;
let selectedQAItem = null;
let dragState = null;
let resizeState = null;
let marqueeSelectState = null;
let suppressNextMarqueeClick = false;
let editorHistory = [];
let isRestoringHistory = false;
let uploadedFonts = [];

let pages = {};
let currentPageId = 'home';
let pageCounter = 1;
let currentDeviceMode = 'desktop';
const responsiveModes = ['desktop', 'tablet', 'mobile'];

const initialSitePageHTML = sitePage.innerHTML;
const initialSitePageBg = sitePage.style.background || '#ffffff';

function uid() {
  return 'id-' + Math.random().toString(36).slice(2, 9);
}

function getZones() {
  return {
    header: sitePage.querySelector('[data-zone="header"]'),
    main: sitePage.querySelector('[data-zone="main"]'),
    footer: sitePage.querySelector('[data-zone="footer"]')
  };
}

function defaultPageHTML() {
  return `
        <div class="html-zone zone-header" data-zone="header">
          <div class="zone-label no-export">Header 區域</div>
          <div class="zone-empty no-export">新增 Header 或導覽列區塊</div>
        </div>

        <main class="html-zone zone-main" data-zone="main">
          <div class="zone-label no-export">Main / Body 區域</div>
          <div class="zone-empty no-export">新增 Section / Div，或選取區塊後新增自由元件</div>
        </main>

        <div class="html-zone zone-footer" data-zone="footer">
          <div class="zone-label no-export">Footer 區域</div>
          <div class="zone-empty no-export">新增 Footer 區塊</div>
        </div>
  `;
}


/* v49：返回上一步 / 歷史紀錄 */
function getEditorSnapshot() {
  return {
    pageId: currentPageId,
    html: sitePage.innerHTML,
    bg: sitePage.style.background || '#ffffff'
  };
}

function saveHistorySnapshot() {
  if (isRestoringHistory) return;

  const snapshot = getEditorSnapshot();
  const last = editorHistory[editorHistory.length - 1];

  if (last && last.pageId === snapshot.pageId && last.html === snapshot.html && last.bg === snapshot.bg) {
    return;
  }

  editorHistory.push(snapshot);

  if (editorHistory.length > 80) {
    editorHistory.shift();
  }
}

function restoreHistorySnapshot(snapshot) {
  if (!snapshot) return;

  isRestoringHistory = true;

  if (pages[currentPageId]) {
    pages[currentPageId].html = sitePage.innerHTML;
    pages[currentPageId].bg = sitePage.style.background || '#ffffff';
  }

  currentPageId = snapshot.pageId || currentPageId;

  if (!pages[currentPageId]) {
    pages[currentPageId] = {
      name: currentPageId === 'home' ? '首頁' : currentPageId,
      html: snapshot.html,
      bg: snapshot.bg || '#ffffff'
    };
  }

  pages[currentPageId].html = snapshot.html;
  pages[currentPageId].bg = snapshot.bg || '#ffffff';

  sitePage.innerHTML = snapshot.html;
  sitePage.style.background = snapshot.bg || '#ffffff';

  initEditableText(sitePage);
  normalizeAllGroupCanvases(sitePage);
  normalizeAllGroupCanvases(sitePage);
  sitePage.querySelectorAll('[data-type="image"]').forEach(syncImageHoverZoomElementStyle);
  sitePage.querySelectorAll('[data-type="line"]').forEach(line => applyLineStyleToElement(line));
  initCardCarouselRuntime(sitePage, false);
  syncAllCarouselPeekLayouts(sitePage);
  initSelectSwitchers(sitePage);
  document.querySelectorAll('.animate-in').forEach(el => el.classList.remove('animate-in'));
  sitePage.querySelectorAll('.js-css-vertical-news-carousel').forEach(block => setVerticalNewsIndex(block, parseInt(block.dataset.verticalIndex || '0', 10) || 0));

  selectedBlock = null;
  selectedElement = null;
  selectedElements = [];
  refreshPageSelector();
  renderLayerList();
  selectBlock(null);

  isRestoringHistory = false;
}

function undoLastAction() {
  if (!editorHistory.length) return;

  const current = getEditorSnapshot();
  let snapshot = editorHistory.pop();

  if (snapshot && snapshot.pageId === current.pageId && snapshot.html === current.html && snapshot.bg === current.bg) {
    snapshot = editorHistory.pop();
  }

  if (snapshot) {
    restoreHistorySnapshot(snapshot);
  }
}

/* v49：圖層表 */
function getLayerDisplayName(el) {
  if (!el) return '圖層';

  const name = el.dataset.name || el.getAttribute('data-name') || '';
  const type = el.dataset.type || el.tagName.toLowerCase();

  if (name) return name;
  if (type === 'group') return '群組';
  if (type === 'shape') return '形狀';
  if (type === 'line') return '線條';
  if (type === 'image') return '圖片';

  return type || '圖層';
}

function renderLayerList() {
  const list = document.getElementById('layerList');
  if (!list) return;

  const scopeBlock = selectedBlock || selectedElement?.closest('.html-block') || null;
  const items = [];
  let index = 1;

  if (scopeBlock) {
    items.push({
      element: scopeBlock,
      type: '區塊',
      name: getLayerDisplayName(scopeBlock),
      index: index++,
      draggable: false
    });

    const elements = Array.from(scopeBlock.querySelectorAll(':scope .block-canvas .free-element'))
      .filter(el => el.closest('.html-block') === scopeBlock)
      .sort((a, b) => {
        const za = parseInt(a.style.zIndex || window.getComputedStyle(a).zIndex || '0', 10) || 0;
        const zb = parseInt(b.style.zIndex || window.getComputedStyle(b).zIndex || '0', 10) || 0;
        return zb - za;
      });

    elements.forEach(el => {
      items.push({
        element: el,
        type: el.dataset.type === 'group' ? '群組' : '元件',
        name: getLayerDisplayName(el),
        index: index++,
        draggable: true
      });
    });
  } else {
    sitePage.querySelectorAll('.html-block').forEach(block => {
      items.push({
        element: block,
        type: '區塊',
        name: getLayerDisplayName(block),
        index: index++,
        draggable: false
      });
    });
  }

  if (!items.length) {
    list.innerHTML = '<div class="small text-muted">尚無圖層</div>';
    return;
  }

  list.innerHTML = items.map(item => {
    const active = item.element === selectedElement || item.element === selectedBlock ? ' active' : '';
    const handle = item.draggable ? '<span class="layer-drag-handle" title="拖拉排序圖層">☰</span>' : '<span class="layer-drag-handle layer-drag-placeholder"></span>';

    return `<button type="button" class="layer-item${active}" data-layer-index="${item.index}" ${item.draggable ? 'draggable="true"' : ''}>
      ${handle}<span class="layer-type">${item.type}</span><span class="layer-name">${item.name}</span>
    </button>`;
  }).join('');

  items.forEach(item => {
    const btn = list.querySelector(`[data-layer-index="${item.index}"]`);
    if (!btn) return;

    btn.addEventListener('click', event => {
      if (event.target.closest('.layer-drag-handle')) return;

      if (item.element.classList.contains('html-block')) {
        selectBlock(item.element);
      } else {
        selectElement(item.element);
      }

      item.element.scrollIntoView({
        behavior: 'smooth',
        block: 'center'
      });
    });

    if (item.draggable) {
      btn.addEventListener('dragstart', event => {
        event.dataTransfer.setData('text/plain', String(item.index));
        btn.classList.add('dragging');
      });

      btn.addEventListener('dragend', () => btn.classList.remove('dragging'));
      btn.addEventListener('dragover', event => {
        event.preventDefault();
        btn.classList.add('drag-over');
      });

      btn.addEventListener('dragleave', () => btn.classList.remove('drag-over'));

      btn.addEventListener('drop', event => {
        event.preventDefault();
        btn.classList.remove('drag-over');

        const fromIndex = parseInt(event.dataTransfer.getData('text/plain'), 10);
        const from = items.find(layer => layer.index === fromIndex);
        const to = item;

        if (!from || !to || !from.draggable || !to.draggable || from === to) return;

        saveHistorySnapshot();

        const draggableItems = items.filter(layer => layer.draggable);
        const zValues = draggableItems
          .map(layer => parseInt(layer.element.style.zIndex || window.getComputedStyle(layer.element).zIndex || '0', 10) || 0)
          .sort((a, b) => b - a);

        const ordered = draggableItems.slice();
        const fromPos = ordered.indexOf(from);
        const toPos = ordered.indexOf(to);

        ordered.splice(fromPos, 1);
        ordered.splice(toPos, 0, from);

        ordered.forEach((layer, idx) => {
          layer.element.style.zIndex = String(zValues[idx] ?? (100 - idx));
        });

        renderLayerList();
        refreshInspector();
        scheduleAutoSave?.();
      });
    }
  });
}

/* v49：上傳字體 */
function getFontMimeType(file) {
  const ext = (file.name.split('.').pop() || '').toLowerCase();

  if (ext === 'woff2') return 'font/woff2';
  if (ext === 'woff') return 'font/woff';
  if (ext === 'otf') return 'font/otf';
  if (ext === 'ttf') return 'font/ttf';

  return file.type || 'font/ttf';
}

function addUploadedFontOption(font) {
  const select = document.getElementById('elementFontFamily');
  if (!select) return;

  if (Array.from(select.options).some(option => option.value === font.familyValue)) {
    return;
  }

  const option = document.createElement('option');
  option.value = font.familyValue;
  option.textContent = font.displayName;
  option.dataset.uploadedFont = 'true';
  select.appendChild(option);
}

function getUploadedFontCSS() {
  return uploadedFonts.map(font => {
    return `@font-face { font-family: ${font.familyValue}; src: url("${font.dataUrl}") format("${font.format}"); font-display: swap; }`;
  }).join('\n');
}

function handleFontUpload(event) {
  const file = event.target.files && event.target.files[0];
  if (!file) return;

  const reader = new FileReader();

  reader.onload = () => {
    const rawName = file.name.replace(/\.[^/.]+$/, '') || '上傳字體';
    const familyName = `uploaded-font-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
    const familyValue = `'${familyName}'`;
    const ext = (file.name.split('.').pop() || 'ttf').toLowerCase();

    const font = {
      displayName: rawName,
      familyName,
      familyValue,
      dataUrl: reader.result,
      format: ext === 'ttf' ? 'truetype' : ext === 'otf' ? 'opentype' : ext
    };

    uploadedFonts.push(font);
    persistUploadedFontsPermanent();

    const style = document.createElement('style');
    style.dataset.uploadedFont = familyName;
    style.textContent = `@font-face { font-family: ${familyValue}; src: url("${font.dataUrl}") format("${font.format}"); font-display: swap; }`;
    document.head.appendChild(style);

    addUploadedFontOption(font);
    persistUploadedFontsPermanent();
    setValue('elementFontFamily', familyValue);

    if (selectedElement) {
      saveHistorySnapshot();
      applyFontToElementDeep(selectedElement, familyValue);
      refreshInspector();
    }

    event.target.value = '';
  };

  reader.readAsDataURL(file);
}

/* v49：形狀材質 */
function applyShapeMaterial(el) {
  if (!el || el.dataset.type !== 'shape') return;

  const material = el.dataset.shapeMaterial || 'none';
  const fill = el.querySelector('.shape-fill');

  el.dataset.shapeMaterial = material;

  const shapeColor = normalizeHexColor(el.dataset.shapeColor || rgbToHex(window.getComputedStyle(el).backgroundColor), '#0d6efd');
  const shapeOpacityPercent = clampNumber(parseFloat(el.dataset.shapeOpacity ?? getColorAlphaPercent(window.getComputedStyle(el).backgroundColor) ?? 100), 0, 100);
  applyShapeColorVars(el, shapeColor, shapeOpacityPercent);

  if (material === 'none' || material === 'dark-matte') {
    el.style.backdropFilter = '';
    el.style.webkitBackdropFilter = '';

    if (fill) {
      fill.style.border = '';
      fill.style.boxShadow = '';
      fill.style.backdropFilter = '';
      fill.style.webkitBackdropFilter = '';
    }

    return;
  }

  el.style.backdropFilter = material === 'frosted'
    ? 'blur(12px) saturate(130%)'
    : 'blur(8px) saturate(150%)';
  el.style.webkitBackdropFilter = el.style.backdropFilter;

  if (fill) {
    fill.style.backdropFilter = el.style.backdropFilter;
    fill.style.webkitBackdropFilter = el.style.webkitBackdropFilter;
  }
}

function syncShapeMaterialPanel() {
  if (!selectedElement || selectedElement.dataset.type !== 'shape') return;
  setValue('shapeMaterial', selectedElement.dataset.shapeMaterial || 'none');
}

/* v49：群組 */
function getCanvasForSelectedElements(elements) {
  const canvases = new Set(elements.map(el => el.closest('.block-canvas')).filter(Boolean));

  if (canvases.size !== 1) {
    return null;
  }

  return Array.from(canvases)[0];
}

function createGroupFromSelection() {
  const elements = getActiveSelectedElements();

  if (elements.length < 2) {
    alert('請先 Ctrl 多選兩個以上元件。');
    return;
  }

  const canvas = getCanvasForSelectedElements(elements);

  if (!canvas) {
    alert('只能將同一個區塊內的元件建立群組。');
    return;
  }

  saveHistorySnapshot();

  const canvasRect = canvas.getBoundingClientRect();
  const rects = elements.map(el => el.getBoundingClientRect());

  const minLeft = Math.min(...rects.map(rect => rect.left));
  const minTop = Math.min(...rects.map(rect => rect.top));
  const maxRight = Math.max(...rects.map(rect => rect.right));
  const maxBottom = Math.max(...rects.map(rect => rect.bottom));

  const groupLeftPx = minLeft - canvasRect.left;
  const groupTopPx = minTop - canvasRect.top;
  const groupWidthPx = Math.max(24, maxRight - minLeft);
  const groupHeightPx = Math.max(24, maxBottom - minTop);

  const group = document.createElement('div');
  group.className = 'free-element';
  group.dataset.id = uid();
  group.dataset.type = 'group';
  group.dataset.name = '群組';
  group.style.left = (groupLeftPx / canvasRect.width * 100) + '%';
  group.style.top = groupTopPx + 'px';
  group.style.width = (groupWidthPx / canvasRect.width * 100) + '%';
  group.style.height = groupHeightPx + 'px';
  group.style.zIndex = Math.max(...elements.map(el => parseInt(el.style.zIndex || '10', 10) || 10)) + 1;
  group.style.background = 'transparent';
  group.style.borderRadius = '12px';

  group.innerHTML = `
    ${elementToolbarHTML()}
    <div class="inner group-inner block-canvas group-canvas" style="min-height: 100%;"></div>
  `;

  const inner = group.querySelector('.group-inner');

  elements.forEach(el => {
    const rect = el.getBoundingClientRect();
    const leftPx = rect.left - minLeft;
    const topPx = rect.top - minTop;

    el.classList.remove('selected', 'multi-selected');
    el.style.left = (leftPx / groupWidthPx * 100) + '%';
    el.style.top = topPx + 'px';
    el.style.width = (rect.width / groupWidthPx * 100) + '%';
    el.style.height = rect.height + 'px';

    inner.appendChild(el);
  });

  canvas.appendChild(group);
  initEditableText(group);
  selectedElements = [];
  selectElement(group);
  renderLayerList();
}

function ungroupSelectedGroup(group) {
  if (!group || group.dataset.type !== 'group') return;

  const inner = normalizeGroupCanvas(group);
  if (!inner) return;

  const canvas = getElementPositionContext(group);
  if (!canvas) return;

  const children = Array.from(inner.querySelectorAll(':scope > .free-element'));

  if (!children.length) {
    saveHistorySnapshot();
    group.remove();
    selectedElements = [];
    selectBlock(null);
    renderLayerList();
    scheduleAutoSave?.();
    return;
  }

  saveHistorySnapshot();

  const canvasRect = canvas.getBoundingClientRect();
  const groupZ = parseInt(group.style.zIndex || '10', 10) || 10;
  const childData = children.map((child, index) => {
    const rect = child.getBoundingClientRect();
    return {
      child,
      index,
      left: ((rect.left - canvasRect.left) / Math.max(canvasRect.width, 1)) * 100,
      top: rect.top - canvasRect.top,
      width: (rect.width / Math.max(canvasRect.width, 1)) * 100,
      height: rect.height
    };
  });

  childData.forEach(item => {
    const child = item.child;
    child.classList.remove('selected', 'multi-selected', 'has-selected-child', 'is-editing');
    child.style.left = item.left + '%';
    child.style.top = item.top + 'px';
    child.style.width = Math.max(3, item.width) + '%';
    child.style.height = Math.max(24, item.height) + 'px';
    child.style.zIndex = String(groupZ + item.index + 1);
    canvas.appendChild(child);
    initEditableText(child);
  });

  group.remove();

  selectedElements = childData.map(item => item.child).filter(child => child && child.isConnected);
  selectedElement = selectedElements[selectedElements.length - 1] || null;
  selectedBlock = selectedElement ? selectedElement.closest('.html-block') : null;

  selectedElements.forEach(child => {
    child.classList.add('selected');
    child.classList.toggle('multi-selected', selectedElements.length > 1);
  });

  updateMultiSelectionLabel();
  syncMultiDistributeTools();
  updateLockButtons(sitePage);
  renderLayerList();
  refreshInspector();
  scheduleAutoSave?.();
}



/* v50：群組點選層級
   - 第一下點群組內元件：先選取外層群組
   - 群組已選取時再點內部元件：才選取對應內容元件
   - Ctrl / Command 點擊時：直接多選實際點到的元件，圖片與形狀也可用
*/
function resolveGroupedClickElement(event) {
  const clickedElement = event.target.closest('.free-element');
  if (!clickedElement) return null;

  const useAdditive = event.ctrlKey || event.metaKey;
  if (useAdditive) return clickedElement;

  const groupInner = clickedElement.closest('.group-inner');
  const parentGroup = groupInner ? groupInner.closest('.free-element[data-type="group"]') : null;

  if (parentGroup && clickedElement !== parentGroup) {
    const selectedInsideSameGroup = !!(
      selectedElement &&
      selectedElement !== parentGroup &&
      selectedElement.closest('.group-inner')?.closest('.free-element[data-type="group"]') === parentGroup
    );

    // v52：內容元件已經被選取後，繼續固定在內容元件，不再跳回外層群組
    if (selectedElement === clickedElement || clickedElement.classList.contains('selected')) {
      return clickedElement;
    }

    // 第一下：選群組；第二下：選內容；之後點群組內其他內容也直接切換內容
    if (selectedElement === parentGroup || parentGroup.classList.contains('selected') || selectedInsideSameGroup) {
      return clickedElement;
    }

    return parentGroup;
  }

  return clickedElement;
}

function updateFloatingGroupButtons() {
  const show = getActiveSelectedElements().length >= 2;

  document.querySelectorAll('.group-action-btn').forEach(btn => {
    btn.classList.toggle('d-none', !show);
  });
}

function syncGroupSelectionState() {
  document.querySelectorAll('.free-element[data-type="group"]').forEach(group => {
    const hasSelectedChild = !!group.querySelector('.group-inner .free-element.selected');
    group.classList.toggle('has-selected-child', hasSelectedChild && !group.classList.contains('selected'));
  });
}

function clearGroupChildEditMarkers() {
  document.querySelectorAll('.free-element[data-group-child-selected-at]').forEach(el => {
    el.removeAttribute('data-group-child-selected-at');
  });
}



function normalizeGroupCanvas(group) {
  if (!group || group.dataset.type !== 'group') return null;

  let inner = group.querySelector(':scope > .group-inner');

  if (!inner) {
    inner = document.createElement('div');
    inner.className = 'inner group-inner block-canvas group-canvas';
    inner.style.minHeight = '100%';
    group.appendChild(inner);
  }

  inner.classList.add('block-canvas', 'group-canvas');
  inner.style.minHeight = inner.style.minHeight || '100%';

  const empty = inner.querySelector(':scope > .group-empty');
  const hasChildElement = inner.querySelector(':scope > .free-element');

  if (!hasChildElement && !empty) {
    inner.insertAdjacentHTML('beforeend', '<div class="group-empty no-export">空白群組，可在此新增文字、圖片、形狀等元件</div>');
  }

  return inner;
}

function normalizeAllGroupCanvases(scope = sitePage) {
  scope.querySelectorAll('.free-element[data-type="group"]').forEach(normalizeGroupCanvas);
}

function removeGroupEmpty(group) {
  const inner = normalizeGroupCanvas(group);
  const empty = inner && inner.querySelector(':scope > .group-empty');
  if (empty) empty.remove();
}

function restoreGroupEmpty(group) {
  const inner = normalizeGroupCanvas(group);
  if (!inner) return;

  const hasChildElement = inner.querySelector(':scope > .free-element');
  if (!hasChildElement && !inner.querySelector(':scope > .group-empty')) {
    inner.insertAdjacentHTML('beforeend', '<div class="group-empty no-export">空白群組，可在此新增文字、圖片、形狀等元件</div>');
  }
}

function getSelectedGroupElement() {
  return selectedElement && selectedElement.dataset.type === 'group'
    ? selectedElement
    : null;
}



/* v63：各裝置模式獨立排版資料 */
function normalizeResponsivePage(page) {
  if (!page) return page;

  page.responsive = page.responsive || {};

  const baseHtml = page.html || defaultPageHTML();
  const baseBg = page.bg || '#ffffff';

  responsiveModes.forEach(mode => {
    if (!page.responsive[mode]) {
      page.responsive[mode] = {
        html: baseHtml,
        bg: baseBg
      };
    }
  });

  return page;
}

function normalizeAllResponsivePages() {
  Object.values(pages).forEach(normalizeResponsivePage);
}

function getPageModeData(pageId = currentPageId, mode = currentDeviceMode) {
  const page = normalizeResponsivePage(pages[pageId]);
  return page && page.responsive && page.responsive[mode]
    ? page.responsive[mode]
    : null;
}

function captureCurrentResponsiveMode() {
  if (!pages[currentPageId]) return;

  normalizeResponsivePage(pages[currentPageId]);

  pages[currentPageId].responsive[currentDeviceMode] = {
    html: sitePage.innerHTML,
    bg: sitePage.style.background || '#ffffff'
  };

  if (currentDeviceMode === 'desktop') {
    pages[currentPageId].html = sitePage.innerHTML;
    pages[currentPageId].bg = sitePage.style.background || '#ffffff';
  }
}

function loadCurrentResponsiveMode() {
  const data = getPageModeData(currentPageId, currentDeviceMode);
  if (!data) return;

  sitePage.innerHTML = data.html;
  sitePage.style.background = data.bg || '#ffffff';
  initPageRuntimeAfterHTMLLoad();
}

function initPageRuntimeAfterHTMLLoad() {
  initEditableText(sitePage);
  normalizeAllGroupCanvases(sitePage);
  sitePage.querySelectorAll('[data-type="image"]').forEach(syncImageHoverZoomElementStyle);
  sitePage.querySelectorAll('[data-type="line"]').forEach(line => applyLineStyleToElement(line));
  initCardCarouselRuntime(sitePage, false);
  initSelectSwitchers(sitePage);
  initSideDrawerRuntime(sitePage);
  initHoverSlideGroups(sitePage);
  repairElementColorState(sitePage);
  updateLockButtons(sitePage);
  sitePage.querySelectorAll('.js-css-vertical-news-carousel').forEach(block => setVerticalNewsIndex(block, parseInt(block.dataset.verticalIndex || '0', 10) || 0));
}

function setDeviceMode(mode) {
  if (!responsiveModes.includes(mode)) mode = 'desktop';

  captureCurrentResponsiveMode();

  currentDeviceMode = mode;
  document.body.classList.remove('device-desktop', 'device-tablet', 'device-mobile');
  document.body.classList.add('device-' + mode);

  document.querySelectorAll('[data-device-mode]').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.deviceMode === mode);
  });

  loadCurrentResponsiveMode();

  selectedBlock = null;
  selectedElement = null;
  selectedElements = [];
  refreshInspector();
  renderLayerList();
  selectBlock(null);
}

function getExportModeSelection() {
  const input = prompt(
    '請輸入要匯出的模式，可用逗號分隔：desktop, tablet, mobile\\n桌機為主，建議至少保留 desktop。',
    'desktop'
  );

  if (input === null) return null;

  const selected = input
    .split(',')
    .map(item => item.trim().toLowerCase())
    .filter(item => responsiveModes.includes(item));

  if (!selected.includes('desktop')) {
    selected.unshift('desktop');
  }

  return Array.from(new Set(selected));
}

function modeLabel(mode) {
  if (mode === 'tablet') return '平板';
  if (mode === 'mobile') return '手機';
  return '桌機';
}

function getModeFolderPrefix(mode) {
  if (mode === 'tablet') return 'tablet/';
  if (mode === 'mobile') return 'mobile/';
  return '';
}

function initPages() {
  if (!pages.home) {
    pages = {
      home: {
        name: '首頁',
        html: initialSitePageHTML,
        bg: initialSitePageBg || '#ffffff'
      }
    };
  }

  currentPageId = currentPageId || 'home';
  normalizeAllResponsivePages();
  refreshPageSelector();
  refreshPageTargetOptions();
}

function captureCurrentPage() {
  captureCurrentResponsiveMode();
}

function refreshPageSelector() {
  const select = document.getElementById('pageSelect');
  if (!select) return;

  select.innerHTML = Object.entries(pages).map(([id, page]) => {
    const selected = id === currentPageId ? ' selected' : '';
    return `<option value="${id}"${selected}>${page.name}</option>`;
  }).join('');

  select.value = currentPageId;
  refreshPageTargetOptions();
}

function refreshPageTargetOptions(preferredValue = '') {
  const select = document.getElementById('goToPageSelect');
  if (!select) return;

  const current = preferredValue || '';
  select.innerHTML = '<option value="">請先選擇子頁面</option>' + Object.entries(pages).map(([id, page]) => {
    const selected = id === current ? ' selected' : '';
    return `<option value="${id}"${selected}>${page.name}</option>`;
  }).join('');

  if (current && pages[current]) {
    select.value = current;
  } else {
    select.value = '';
  }
}

function loadPage(pageId, saveCurrent = true) {
  if (!pages[pageId]) {
    alert('找不到指定子頁面。');
    return;
  }

  if (saveCurrent) {
    captureCurrentPage();
  }

  hideAllAlignmentGuides();

  currentPageId = pageId;
  normalizeResponsivePage(pages[pageId]);

  const modeData = getPageModeData(pageId, currentDeviceMode) || pages[pageId].responsive.desktop;
  sitePage.innerHTML = modeData.html;
  sitePage.style.background = modeData.bg || '#ffffff';

  initPageRuntimeAfterHTMLLoad();

  selectedBlock = null;
  selectedElement = null;

  const pageBg = document.getElementById('pageBgColor');
  if (pageBg) pageBg.value = rgbToHex(sitePage.style.background || '#ffffff');

  refreshPageSelector();
  refreshScrollTargetOptions();
  selectBlock(null);
}

function createUniquePageId() {
  pageCounter += 1;

  let id = 'page-' + pageCounter;
  while (pages[id]) {
    pageCounter += 1;
    id = 'page-' + pageCounter;
  }

  return id;
}

function addSubPage() {
  captureCurrentPage();

  const defaultName = '子頁面 ' + pageCounter;
  const name = (prompt('請輸入子頁面名稱', defaultName) || '').trim();

  if (!name) return;

  const id = createUniquePageId();

  pages[id] = normalizeResponsivePage({
    name,
    html: defaultPageHTML(),
    bg: '#ffffff'
  });

  loadPage(id, false);
  alert(`子頁面「${name}」已新增。`);
}

/* v142：複製目前分頁 */
function deepClonePageDataV142(page) {
  try {
    return JSON.parse(JSON.stringify(page || {}));
  } catch (error) {
    return {
      name: page && page.name ? page.name : '未命名分頁',
      html: page && page.html ? page.html : defaultPageHTML(),
      bg: page && page.bg ? page.bg : '#ffffff'
    };
  }
}

function getUniqueCopiedPageNameV142(baseName) {
  const cleanBase = String(baseName || '分頁').trim() || '分頁';
  const existingNames = new Set(Object.values(pages).map(page => page && page.name));
  let name = cleanBase + ' 複製';
  let index = 2;

  while (existingNames.has(name)) {
    name = cleanBase + ' 複製 ' + index;
    index += 1;
  }

  return name;
}

function duplicateCurrentPage() {
  const current = pages[currentPageId];

  if (!current) {
    alert('目前沒有可複製的分頁。');
    return;
  }

  captureCurrentPage();
  normalizeResponsivePage(current);

  const defaultName = getUniqueCopiedPageNameV142(current.name || '分頁');
  const name = (prompt('請輸入複製分頁名稱', defaultName) || '').trim();

  if (!name) return;

  const id = createUniquePageId();
  const copiedPage = deepClonePageDataV142(current);

  copiedPage.name = name;
  pages[id] = normalizeResponsivePage(copiedPage);

  loadPage(id, false);
  refreshPageTargetOptions();
  scheduleAutoSave();

  alert(`已複製分頁為「${name}」。`);
}

function renameCurrentPage() {
  const current = pages[currentPageId];
  if (!current) return;

  const name = (prompt('請輸入新的頁面名稱', current.name) || '').trim();

  if (!name) return;

  current.name = name;
  refreshPageSelector();
  alert(`頁面已改名為「${name}」。`);
}

function deleteCurrentPage() {
  if (currentPageId === 'home') {
    alert('首頁不能刪除。');
    return;
  }

  const current = pages[currentPageId];

  if (!current) return;
  if (!confirm(`確定要刪除「${current.name}」嗎？`)) return;

  delete pages[currentPageId];

  const nextPageId = Object.keys(pages)[0] || 'home';
  currentPageId = nextPageId;
  loadPage(nextPageId, false);
  alert('子頁面已刪除。');
}

