function getVerticalNewsGroups(block) {
  return Array.from(block.querySelectorAll('.vertical-news-slide'));
}

function getCurrentVerticalNewsGroup(block) {
  const groups = getVerticalNewsGroups(block);
  const current = parseInt(block.dataset.verticalIndex || '0', 10) || 0;
  return groups[current] || groups[0] || null;
}

function updateVerticalNewsInfo(block) {
  const groups = getVerticalNewsGroups(block);
  const current = parseInt(block.dataset.verticalIndex || '0', 10) || 0;
  const text = `${Math.min(current + 1, groups.length)} / ${groups.length}`;

  const inBlock = block.querySelector('.vertical-carousel-group-info');
  if (inBlock) inBlock.textContent = text;

  if (selectedBlock === block) {
    const panel = document.getElementById('verticalCarouselGroupInfo');
    if (panel) panel.textContent = `目前第 ${Math.min(current + 1, groups.length)} 組，共 ${groups.length} 組`;
  }
}

function setVerticalNewsIndex(block, index) {
  if (!block || block.dataset.type !== 'vertical-news-carousel') return;

  const groups = getVerticalNewsGroups(block);
  if (!groups.length) return;

  const next = ((index % groups.length) + groups.length) % groups.length;
  block.dataset.verticalIndex = next;

  groups.forEach((group, groupIndex) => {
    group.classList.toggle('active', groupIndex === next);
  });

  const viewport = block.querySelector('.vertical-news-viewport');
  if (viewport && groups[next]) {
    viewport.scrollTo({
      top: groups[next].offsetTop,
      behavior: 'smooth'
    });
  }

  updateVerticalNewsInfo(block);
}

function addVerticalNewsGroup(block) {
  if (!block || block.dataset.type !== 'vertical-news-carousel') return;

  const track = block.querySelector('.vertical-news-track');
  const nextIndex = getVerticalNewsGroups(block).length;

  track.insertAdjacentHTML('beforeend', verticalNewsGroupHTML(nextIndex, true));
  const group = track.querySelector('.vertical-news-slide:last-child');

  initEditableText(group);
  setVerticalNewsIndex(block, nextIndex);
}

function copyVerticalNewsGroupContent(block) {
  const group = getCurrentVerticalNewsGroup(block);
  const canvas = group && group.querySelector('.block-canvas');

  if (!canvas) return;

  copiedVerticalGroupHTML = canvas.innerHTML;
  alert('目前垂直圖文群組內容已複製。');
}

function pasteVerticalNewsGroupContent(block) {
  const group = getCurrentVerticalNewsGroup(block);

  if (!group) return;
  if (!copiedVerticalGroupHTML) {
    alert('尚未複製任何垂直圖文群組內容。');
    return;
  }

  const canvas = group.querySelector('.block-canvas');
  if (!canvas) return;

  const empty = canvas.querySelector('.vertical-news-empty-group');
  if (empty) empty.remove();

  const temp = document.createElement('div');
  temp.innerHTML = copiedVerticalGroupHTML;

  Array.from(temp.children).forEach(child => {
    if (child.classList && child.classList.contains('vertical-news-empty-group')) return;
    normalizeDuplicatedElementIds(child);
    child.classList.remove('selected', 'multi-selected', 'is-editing');
    canvas.appendChild(child);
    initEditableText(child);
  });

  setVerticalNewsIndex(block, parseInt(block.dataset.verticalIndex || '0', 10) || 0);
  selectBlock(block);
  alert('已貼上到目前垂直圖文群組，原本內容已保留。');
}

function duplicateVerticalNewsGroup(block) {
  const group = getCurrentVerticalNewsGroup(block);
  if (!group) return;

  const current = parseInt(block.dataset.verticalIndex || '0', 10) || 0;
  const clone = group.cloneNode(true);

  normalizeDuplicatedElementIds(clone);
  clone.classList.remove('active');

  group.after(clone);

  getVerticalNewsGroups(block).forEach((item, index) => {
    item.dataset.newsGroup = index;
  });

  initEditableText(clone);
  setVerticalNewsIndex(block, current + 1);
  selectBlock(block);
}

function deleteVerticalNewsGroup(block) {
  const groups = getVerticalNewsGroups(block);

  if (groups.length <= 1) {
    alert('至少需要保留一個群組。');
    return;
  }

  const current = parseInt(block.dataset.verticalIndex || '0', 10) || 0;
  groups[current].remove();

  getVerticalNewsGroups(block).forEach((item, index) => {
    item.dataset.newsGroup = index;
  });

  setVerticalNewsIndex(block, Math.max(0, current - 1));
}

function handleVerticalNewsAction(block, action) {
  if (!block || block.dataset.type !== 'vertical-news-carousel') return;

  const current = parseInt(block.dataset.verticalIndex || '0', 10) || 0;

  if (action === 'prev') setVerticalNewsIndex(block, current - 1);
  if (action === 'next') setVerticalNewsIndex(block, current + 1);
  if (action === 'add') addVerticalNewsGroup(block);
  if (action === 'copy') copyVerticalNewsGroupContent(block);
  if (action === 'paste') pasteVerticalNewsGroupContent(block);
  if (action === 'duplicate') duplicateVerticalNewsGroup(block);
  if (action === 'delete') deleteVerticalNewsGroup(block);
}

function syncVerticalCarouselSettingPanel() {
  if (!selectedBlock || selectedBlock.dataset.type !== 'vertical-news-carousel') return;
  updateVerticalNewsInfo(selectedBlock);
}

function scrollVerticalNewsBlock(block, direction = 'down') {
  if (!block || block.dataset.type !== 'vertical-news-carousel') return;

  const current = parseInt(block.dataset.verticalIndex || '0', 10) || 0;
  setVerticalNewsIndex(block, direction === 'up' ? current - 1 : current + 1);
}



