function addNavDropdownTemplate() {
  const block = getTargetBlockForElement();
  const canvas = block && (block.querySelector('.block-canvas') || block);

  if (!canvas) {
    alert('請先建立或選取一個區塊。');
    return;
  }

  removeBlockEmpty(block);
  canvas.insertAdjacentHTML('beforeend', navDropdownTemplateHTML());

  const el = canvas.querySelector(':scope > .free-element:last-child');
  if (!el) return;

  initEditableText(el);
  applyOptionStylesToHost(el);
  selectElement(el);
  el.scrollIntoView({ behavior: 'smooth', block: 'center' });
}

function rebuildNavDropdownOptions(root, labels) {
  if (!root) return;

  const menu = root.querySelector('.nav-dropdown-menu');
  if (!menu) return;

  const oldActions = getSelectOptionActions(root);
  const oldStyles = getOptionStyleData(root);

  menu.innerHTML = labels.map((label, index) => {
    return `<button type="button" class="nav-dropdown-option" data-option-index="${index}"><span data-editable-text contenteditable="false">${escapeHTML(label)}</span></button>`;
  }).join('');

  const nextActions = {};
  const nextStyles = {};

  labels.forEach((label, index) => {
    if (oldActions[index]) nextActions[index] = oldActions[index];
    if (oldStyles[index]) nextStyles[index] = oldStyles[index];
  });

  setSelectOptionActions(root, nextActions);
  setOptionStyleData(root, nextStyles);
  initEditableText(root);
  applyOptionStylesToHost(root);
}

function escapeHTML(value) {
  return String(value ?? '').replace(/[&<>"']/g, match => {
    return {
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#039;'
    }[match];
  });
}


