function applyLineNumberInput(inputId, rangeId, min, max) {
  let value = parseFloat(lineSettingValue(inputId, min));
  if (Number.isNaN(value)) value = min;
  value = clampNumber(value, min, max);

  setValue(inputId, value);
  setValue(rangeId, value);
  applyLineStyleFromPanel();
}

function clamp(num, min, max) {
  return Math.min(Math.max(num, min), max);
}

function getSelectedTarget() {
  return selectedElement || selectedBlock;
}

function getActiveSelectedElements() {
  selectedElements = selectedElements.filter(el => el && el.isConnected);
  return selectedElements;
}

function cloneSelected() {
  const multi = getActiveSelectedElements();

  if (multi.length > 1) {
    const clones = multi.map(target => {
      const clone = target.cloneNode(true);
      clone.dataset.id = uid();
      clone.classList.remove('selected', 'multi-selected', 'is-editing');
      clone.style.top = ((parseFloat(target.style.top) || 0) + 24) + 'px';
      target.after(clone);
      initEditableText(clone);
      return clone;
    });

    document.querySelectorAll('.free-element').forEach(el => el.classList.remove('selected', 'multi-selected'));
    selectedElements = [];
    clones.forEach(clone => {
      clone.classList.add('selected', 'multi-selected');
      selectedElements.push(clone);
    });

    selectedElement = clones[clones.length - 1] || null;
    selectedBlock = selectedElement ? selectedElement.closest('.html-block') : null;
    updateMultiSelectionLabel();
    refreshInspector();
    return;
  }

  const target = getSelectedTarget();
  if (!target) return;

  const clone = target.cloneNode(true);
  clone.dataset.id = uid();
  clone.classList.remove('selected', 'multi-selected', 'is-editing');

  if (target.classList.contains('free-element')) {
    const top = (parseFloat(target.style.top) || 0) + 24;
    clone.style.top = top + 'px';

    target.after(clone);
    initEditableText(clone);
    selectElement(clone);
  } else {
    target.after(clone);
    initEditableText(clone);
    selectBlock(clone);
  }
}

function deleteSelected() {
  const multi = getActiveSelectedElements();

  if (multi.length > 1) {
    const affectedBlocks = new Set();

    const affectedGroups = new Set();

    multi.forEach(el => {
      const parentGroup = el.closest('.group-inner')?.closest('.free-element[data-type="group"]');
      const parentBlock = el.closest('.html-block');

      if (parentGroup) affectedGroups.add(parentGroup);
      if (parentBlock) affectedBlocks.add(parentBlock);

      el.remove();
    });

    affectedGroups.forEach(group => restoreGroupEmpty(group));
    affectedBlocks.forEach(block => restoreBlockEmpty(block));

    selectedElements = [];
    selectedBlock = null;
    selectedElement = null;
    selectBlock(null);
    return;
  }

  const target = getSelectedTarget();
  if (!target) return;

  const parentGroup = target.closest('.group-inner')?.closest('.free-element[data-type="group"]');
  const parentBlock = target.closest('.html-block');
  const parentZone = target.closest('.html-zone');

  target.remove();

  if (parentGroup && target.classList.contains('free-element')) {
    restoreGroupEmpty(parentGroup);
  }

  if (parentBlock && target.classList.contains('free-element')) {
    restoreBlockEmpty(parentBlock);
  }

  if (parentZone && target.classList.contains('html-block')) {
    restoreZoneEmpty(parentZone);
  }

  selectedElements = [];
  selectedBlock = null;
  selectedElement = null;
  selectBlock(null);
}

function moveBlock(direction) {
  if (!selectedBlock || selectedElement) return;

  const target = selectedBlock;

  if (direction === 'up') {
    const prev = previousBlockSibling(target);
    if (prev) target.parentNode.insertBefore(target, prev);
  }

  if (direction === 'down') {
    const next = nextBlockSibling(target);
    if (next) target.parentNode.insertBefore(next, target);
  }
}

function previousBlockSibling(target) {
  let el = target.previousElementSibling;
  while (el && !el.classList.contains('html-block')) {
    el = el.previousElementSibling;
  }
  return el;
}

function nextBlockSibling(target) {
  let el = target.nextElementSibling;
  while (el && !el.classList.contains('html-block')) {
    el = el.nextElementSibling;
  }
  return el;
}

function bringFront() {
  const multi = getActiveSelectedElements();

  if (multi.length > 1) {
    multi.forEach(el => el.style.zIndex = 100);
    refreshInspector();
    return;
  }

  if (!selectedElement) return;
  selectedElement.style.zIndex = 100;
  refreshInspector();
}

function sendBack() {
  const multi = getActiveSelectedElements();

  if (multi.length > 1) {
    multi.forEach(el => el.style.zIndex = 0);
    refreshInspector();
    return;
  }

  if (!selectedElement) return;
  selectedElement.style.zIndex = 0;
  refreshInspector();
}

function copySelected() {
  const multi = getActiveSelectedElements();

  if (multi.length > 1) {
    copiedHTML = multi.map(el => el.outerHTML).join('');
    copiedKind = 'elements-multi';
    return;
  }

  const target = getSelectedTarget();
  if (!target) return;

  copiedHTML = target.outerHTML;
  copiedKind = target.classList.contains('html-block') ? 'block' : 'element';
}

function pasteCopied() {
  if (!copiedHTML) {
    cloneSelected();
    return;
  }

  const temp = document.createElement('div');
  temp.innerHTML = copiedHTML.trim();

  if (copiedKind === 'elements-multi') {
    const block = getTargetBlockForElement();
    const canvas = getTargetCanvasForElement(block);

    removeBlockEmpty(block);

    const clones = Array.from(temp.children);
    clones.forEach(clone => {
      normalizeDuplicatedElementIds(clone);
      canvas.appendChild(clone);
      initEditableText(clone);
    });

    document.querySelectorAll('.free-element').forEach(el => el.classList.remove('selected', 'multi-selected'));
    selectedElements = clones;
    clones.forEach(clone => clone.classList.add('selected', 'multi-selected'));
    selectedElement = clones[clones.length - 1] || null;
    selectedBlock = selectedElement ? selectedElement.closest('.html-block') : null;
    updateMultiSelectionLabel();
    refreshInspector();
    return;
  }

  const clone = temp.firstElementChild;
  if (!clone) return;

  clone.dataset.id = uid();
  clone.classList.remove('selected', 'multi-selected', 'is-editing');

  if (copiedKind === 'block') {
    const zone = selectedBlock ? selectedBlock.closest('.html-zone') : targetZoneForBlock('section');
    clearZoneEmpty(zone);
    zone.appendChild(clone);
    initEditableText(clone);
    selectBlock(clone);
  } else {
    const block = getTargetBlockForElement();
    const canvas = getTargetCanvasForElement(block);

    removeBlockEmpty(block);
    canvas.appendChild(clone);

    initEditableText(clone);
    selectElement(clone);
  }
}

function isTypingNow() {
  const active = document.activeElement;
  if (!active) return false;

  const tag = active.tagName;
  const isInput = ['INPUT', 'TEXTAREA', 'SELECT'].includes(tag);
  const isEditable = active.getAttribute('contenteditable') === 'true';

  return isInput || isEditable;
}


/* v76：元件快速對齊、翻轉、旋轉 */
function applyElementTransformState(el) {
  if (!el) return;

  const flipX = el.dataset.flipX === 'true' ? -1 : 1;
  const flipY = el.dataset.flipY === 'true' ? -1 : 1;
  const rotate = parseInt(el.dataset.rotateDeg || '0', 10) || 0;

  const transform = `scaleX(${flipX}) scaleY(${flipY}) rotate(${rotate}deg)`;

  el.style.transform = transform;
  el.style.transformOrigin = 'center center';
}

function applyPositionAction(action) {
  if (!action) return;

  const multi = getActiveSelectedElements();
  if (multi.length > 1 && moveSelectedGroupWithinContext(action)) return;

  if (!selectedElement) return;

  const context = getElementPositionContext(selectedElement);
  if (!context) return;

  const contextRect = context.getBoundingClientRect();
  const elRect = selectedElement.getBoundingClientRect();
  const currentWidthPercent = parseFloat(selectedElement.style.width) || (elRect.width / Math.max(contextRect.width, 1) * 100);
  const currentHeightPx = parseFloat(selectedElement.style.height) || elRect.height;

  saveHistorySnapshot();

  if (action === 'center-both' || action === 'center-x') {
    selectedElement.style.left = Math.max(0, (100 - currentWidthPercent) / 2) + '%';
  }

  if (action === 'center-both' || action === 'center-y') {
    selectedElement.style.top = Math.max(0, (contextRect.height - currentHeightPx) / 2) + 'px';
  }

  if (action === 'left') {
    selectedElement.style.left = '0%';
  }

  if (action === 'right') {
    selectedElement.style.left = Math.max(0, 100 - currentWidthPercent) + '%';
  }

  if (action === 'top') {
    selectedElement.style.top = '0px';
  }

  if (action === 'bottom') {
    selectedElement.style.top = Math.max(0, contextRect.height - currentHeightPx) + 'px';
  }

  if (action === 'flip-x') {
    selectedElement.dataset.flipX = selectedElement.dataset.flipX === 'true' ? 'false' : 'true';
    applyElementTransformState(selectedElement);
  }

  if (action === 'flip-y') {
    selectedElement.dataset.flipY = selectedElement.dataset.flipY === 'true' ? 'false' : 'true';
    applyElementTransformState(selectedElement);
  }

  if (action === 'rotate-right') {
    const current = parseInt(selectedElement.dataset.rotateDeg || '0', 10) || 0;
    selectedElement.dataset.rotateDeg = String((current + 90) % 360);
    applyElementTransformState(selectedElement);
  }

  refreshInspector();
  scheduleAutoSave?.();
}

