// 點選 / 工具按鈕
sitePage.addEventListener('click', e => {
  const hoverSlideAction = e.target.closest('[data-hover-slide-action]');
  if (hoverSlideAction) {
    const block = hoverSlideAction.closest('.js-css-hover-slide-groups, .html-block');
    selectContainerLikeBlock(block);
    handleHoverSlideAction(block, hoverSlideAction.dataset.hoverSlideAction);
    return;
  }

  const selectSwitcherAction = e.target.closest('[data-select-switcher-action]');
  if (selectSwitcherAction) {
    const block = selectSwitcherAction.closest('.js-css-select-switcher, .html-block');
    selectContainerLikeBlock(block);
    handleSelectSwitcherAction(block, selectSwitcherAction.dataset.selectSwitcherAction);
    return;
  }

  const verticalCarouselAction = e.target.closest('[data-vertical-carousel-action]');
  if (verticalCarouselAction) {
    const block = verticalCarouselAction.closest('.js-css-vertical-news-carousel, .html-block');
    selectContainerLikeBlock(block);
    handleVerticalNewsAction(block, verticalCarouselAction.dataset.verticalCarouselAction);
    return;
  }

  const verticalNewsAction = e.target.closest('[data-vertical-news-action]');
  if (verticalNewsAction) {
    const block = verticalNewsAction.closest('.html-block, .js-css-vertical-news-carousel');
    scrollVerticalNewsBlock(block, verticalNewsAction.dataset.verticalNewsAction === 'up' ? 'up' : 'down');
    return;
  }

  const carouselAction = e.target.closest('[data-carousel-action]');
  if (carouselAction) {
    const block = carouselAction.closest('.js-css-card-carousel, .html-block');
    selectContainerLikeBlock(block);
    handleCarouselAction(block, carouselAction.dataset.carouselAction);
    return;
  }

  const publicCarouselAction = e.target.closest('[data-carousel-public]');
  if (publicCarouselAction) {
    const block = publicCarouselAction.closest('.js-css-card-carousel, .html-block');
    const current = parseInt(block.dataset.carouselIndex || '0', 10) || 0;
    setCarouselIndex(block, publicCarouselAction.dataset.carouselPublic === 'next' ? current + 1 : current - 1);
    return;
  }

  const dotAction = e.target.closest('[data-carousel-dot]');
  if (dotAction) {
    const block = dotAction.closest('.js-css-card-carousel, .html-block');
    setCarouselIndex(block, parseInt(dotAction.dataset.carouselDot, 10) || 0);
    return;
  }

  const blockAction = e.target.closest('[data-block-action]');
  if (blockAction) {
    const block = blockAction.closest('.html-block');
    selectBlock(block);

    const action = blockAction.dataset.blockAction;
    if (action === 'clone') cloneSelected();
    if (action === 'delete') deleteSelected();
    if (action === 'up') moveBlock('up');
    if (action === 'down') moveBlock('down');
    return;
  }

  const elementAction = e.target.closest('[data-element-action]');
  if (elementAction) {
    const action = elementAction.dataset.elementAction;

    if (action === 'group') {
      createGroupFromSelection();
      return;
    }

    const el = elementAction.closest('.free-element');

    if (action === 'ungroup') {
      selectElement(el);
      ungroupSelectedGroup(el);
      return;
    }

    if (!(selectedElements.length > 1 && selectedElements.includes(el))) {
      selectElement(el);
    }

    if (action === 'lock') {
      toggleElementLock(el);
      return;
    }

    if (action === 'clone') cloneSelected();
    if (action === 'delete') deleteSelected();
    return;
  }

  const element = resolveGroupedClickElement(e);
  if (element) {
    selectElement(element, e.ctrlKey || e.metaKey);
    return;
  }

  const block = e.target.closest('.html-block');
  if (block) {
    selectBlock(block);
    return;
  }

  selectBlock(null);
});


/* v89：滑鼠拖曳反藍框選多個元件 */
function isMarqueeSelectableStart(event) {
  if (document.body.classList.contains('preview-mode')) return false;
  if (event.button !== 0) return false;
  if (isTypingNow()) return false;

  const target = event.target;
  if (!target || !sitePage.contains(target)) return false;

  // 點到工具列、縮放點、表單或可編輯文字時，不啟動框選，避免影響原本操作。
  if (target.closest(
    '.editor-actions, .move-handle, .element-toolbar, .resize-handle, ' +
    '[data-block-action], [data-element-action], [data-carousel-action], [data-select-switcher-action], ' +
    '[data-vertical-carousel-action], [data-hover-slide-action], [data-accordion-action], ' +
    'input, textarea, select, button, a, [contenteditable="true"]'
  )) {
    return false;
  }

  const scope = getMarqueeSelectScope(target);
  if (!scope) return false;

  // 點在元件本體上仍維持原本「選取 / 拖移」邏輯；只有畫布空白處可拉框。
  // 若是在群組內空白處，closest('.free-element') 會拿到群組外框，這種情況允許框選群組內子元件。
  const nearestElement = target.closest('.free-element');
  const parentGroup = scope.classList.contains('group-inner')
    ? scope.closest('.free-element[data-type="group"]')
    : null;

  if (nearestElement && nearestElement !== parentGroup) return false;

  return true;
}

function getMarqueeSelectScope(target) {
  if (!target || !sitePage.contains(target)) return null;
  return target.closest('.group-inner, .block-canvas');
}

function getScopeSelectableElements(scope) {
  if (!scope) return [];

  return Array.from(scope.children).filter(child => {
    if (!child.classList || !child.classList.contains('free-element')) return false;
    if (!child.isConnected) return false;

    const rect = child.getBoundingClientRect();
    if (rect.width <= 0 || rect.height <= 0) return false;

    const style = window.getComputedStyle(child);
    return style.display !== 'none' && style.visibility !== 'hidden';
  });
}

function ensureMarqueeSelectBox() {
  let box = document.getElementById('marqueeSelectBox');

  if (!box) {
    box = document.createElement('div');
    box.id = 'marqueeSelectBox';
    box.className = 'drag-select-marquee no-export';
    box.setAttribute('aria-hidden', 'true');
    document.body.appendChild(box);
  }

  return box;
}

function setMarqueeBoxRect(box, x1, y1, x2, y2) {
  const left = Math.min(x1, x2);
  const top = Math.min(y1, y2);
  const width = Math.abs(x2 - x1);
  const height = Math.abs(y2 - y1);

  box.style.left = left + 'px';
  box.style.top = top + 'px';
  box.style.width = width + 'px';
  box.style.height = height + 'px';

  return { left, top, right: left + width, bottom: top + height, width, height };
}

function rectsIntersect(a, b) {
  return !(b.left > a.right || b.right < a.left || b.top > a.bottom || b.bottom < a.top);
}

function getElementsInsideMarquee(scope, marqueeRect) {
  return getScopeSelectableElements(scope).filter(el => {
    const rect = el.getBoundingClientRect();
    return rectsIntersect(marqueeRect, rect);
  });
}

function sameElementList(a, b) {
  if (a.length !== b.length) return false;
  return a.every((item, index) => item === b[index]);
}

function applyMarqueeSelection(elements, final = false) {
  const cleanElements = elements.filter(el => el && el.isConnected);

  if (!final && sameElementList(cleanElements, selectedElements)) return;

  document.querySelectorAll('.html-block').forEach(item => item.classList.remove('selected'));
  document.querySelectorAll('.free-element').forEach(item => item.classList.remove('selected', 'multi-selected'));

  selectedElements = cleanElements;
  selectedElement = cleanElements[cleanElements.length - 1] || null;
  selectedBlock = selectedElement ? selectedElement.closest('.html-block') : null;

  cleanElements.forEach(item => {
    item.classList.add('selected');
    item.classList.toggle('multi-selected', cleanElements.length > 1);
  });

  if (selectedBlock) lastUsedBlockId = selectedBlock.dataset.id || null;

  clearGroupChildEditMarkers();
  syncGroupSelectionState();

  const selectedName = document.getElementById('selectedName');
  const selectedHint = document.getElementById('selectedHint');

  if (cleanElements.length > 1) {
    if (selectedName) selectedName.textContent = `已選取 ${cleanElements.length} 個元件`;
    if (selectedHint) selectedHint.textContent = '拖曳反藍框選完成；可一起移動、縮放、對齊、刪除、鎖定 / 解鎖，3 個以上可平均分配間距。';
  } else if (cleanElements.length === 1) {
    if (selectedName) selectedName.textContent = cleanElements[0].dataset.name || '自由元件';
    if (selectedHint) selectedHint.textContent = '已框選 1 個元件；可拖移、縮放或調整右側設定。';
  } else {
    if (selectedName) selectedName.textContent = '尚未選取';
    if (selectedHint) selectedHint.textContent = '空白畫布可按住滑鼠拖曳，反藍框選多個元件。';
  }

  syncMultiDistributeTools();
  updateLockButtons(sitePage);

  if (final) {
    refreshInspector();
    renderLayerList();
  }
}

function finishMarqueeSelection(event, cancelled = false) {
  if (!marqueeSelectState) return;

  const state = marqueeSelectState;
  const box = state.box;

  if (state.active && !cancelled) {
    const rect = setMarqueeBoxRect(box, state.startX, state.startY, event?.clientX ?? state.lastX, event?.clientY ?? state.lastY);
    const elements = getElementsInsideMarquee(state.scope, rect);
    applyMarqueeSelection(elements, true);
    suppressNextMarqueeClick = true;
    window.setTimeout(() => {
      suppressNextMarqueeClick = false;
    }, 0);
  }

  if (box) box.style.display = 'none';
  document.body.classList.remove('is-marquee-selecting');

  try {
    state.captureTarget?.releasePointerCapture?.(state.pointerId);
  } catch (error) {}

  marqueeSelectState = null;
}


function isPointerNearElementEdge(event, el, threshold = 12) {
  if (!el) return false;

  const rect = el.getBoundingClientRect();
  const x = event.clientX - rect.left;
  const y = event.clientY - rect.top;

  return (
    x <= threshold ||
    y <= threshold ||
    rect.width - x <= threshold ||
    rect.height - y <= threshold
  );
}



sitePage.addEventListener('pointerdown', e => {
  if (!isMarqueeSelectableStart(e)) return;

  const scope = getMarqueeSelectScope(e.target);
  if (!scope) return;

  const box = ensureMarqueeSelectBox();
  box.style.display = 'none';

  marqueeSelectState = {
    scope,
    box,
    pointerId: e.pointerId,
    startX: e.clientX,
    startY: e.clientY,
    lastX: e.clientX,
    lastY: e.clientY,
    active: false,
    captureTarget: e.target
  };

  try {
    e.target.setPointerCapture?.(e.pointerId);
  } catch (error) {}
}, true);

sitePage.addEventListener('pointermove', e => {
  if (!marqueeSelectState || marqueeSelectState.pointerId !== e.pointerId) return;

  const state = marqueeSelectState;
  state.lastX = e.clientX;
  state.lastY = e.clientY;

  const distanceX = Math.abs(e.clientX - state.startX);
  const distanceY = Math.abs(e.clientY - state.startY);

  if (!state.active && Math.max(distanceX, distanceY) < 6) return;

  if (!state.active) {
    state.active = true;
    state.box.style.display = 'block';
    document.body.classList.add('is-marquee-selecting');
    e.preventDefault();
  }

  const rect = setMarqueeBoxRect(state.box, state.startX, state.startY, e.clientX, e.clientY);
  const elements = getElementsInsideMarquee(state.scope, rect);
  applyMarqueeSelection(elements, false);

  e.preventDefault();
}, true);

sitePage.addEventListener('pointerup', e => {
  if (!marqueeSelectState || marqueeSelectState.pointerId !== e.pointerId) return;
  finishMarqueeSelection(e, false);
}, true);

sitePage.addEventListener('pointercancel', e => {
  if (!marqueeSelectState || marqueeSelectState.pointerId !== e.pointerId) return;
  finishMarqueeSelection(e, true);
}, true);


sitePage.addEventListener('pointerdown', e => {
  if (document.body.classList.contains('preview-mode')) return;

  const switcherSelect = e.target.closest('.select-switcher-select-element .select-switcher-control');
  if (!switcherSelect) return;

  const el = switcherSelect.closest('.free-element[data-type="select-switcher-control"]');
  if (!el) return;

  e.preventDefault();
  selectElement(el);
}, true);


// 拖移元件：文字、圖片、形狀都只允許拖曳上方 move-handle；YouTube / 群組保留直接拖曳
sitePage.addEventListener('pointerdown', e => {
  if (document.body.classList.contains('preview-mode')) return;

  const moveHandle = e.target.closest('.move-handle');
  const imageElement = e.target.closest('.free-element[data-type="image"]');
  const youtubeElement = e.target.closest('.free-element[data-type="youtube"]');
  const shapeElement = e.target.closest('.free-element[data-type="shape"]');
  const lineElement = e.target.closest('.free-element[data-type="line"]');
  const groupElement = e.target.closest('.free-element[data-type="group"]');
  const switcherControlElement = e.target.closest('.free-element[data-type="select-switcher-control"]');
  const directDragElement = switcherControlElement || youtubeElement || lineElement || groupElement;

  // v117：按 Ctrl / Command 點線條等可直接拖曳元件時，不先啟動拖曳，交給 click 做加選/取消加選，避免線條無法多選。
  if ((e.ctrlKey || e.metaKey) && !moveHandle && directDragElement) return;

  // v54：圖片與形狀移動方式一致，都不能直接拖曳本體，必須用上方「移動」鍵
  if (!moveHandle && (imageElement || shapeElement)) return;

  // 其他文字元件仍只能拖「移動」把手；下拉換組元件 / YouTube / 線條 / 群組可直接拖曳
  if (!moveHandle && !directDragElement) return;

  let el = moveHandle
    ? moveHandle.closest('.free-element')
    : directDragElement;

  const resolvedDragElement = resolveGroupedClickElement(e);
  if (resolvedDragElement && resolvedDragElement !== el && !(e.ctrlKey || e.metaKey)) {
    el = resolvedDragElement;
  }

  if (!moveHandle && ['image', 'shape'].includes(el?.dataset?.type)) return;

  if (!el) return;
  if (isElementLocked(el)) return;
  if (isTypingNow()) return;

  // 點到媒體元件的工具列或縮放點時，不啟動拖曳
  if (!moveHandle && (e.target.closest('.element-toolbar') || e.target.closest('.resize-handle'))) return;

  e.preventDefault();
  e.stopPropagation();
  saveHistorySnapshot();

  if (!(selectedElements.length > 1 && selectedElements.includes(el))) {
    selectElement(el);
  }

  const canvas = getElementPositionContext(el);
  const canvasRect = canvas.getBoundingClientRect();
  const values = getElementValues(el);
  const dragItems = selectedElements.length > 1 && selectedElements.includes(el)
    ? selectedElements.map(item => {
      const itemValues = getElementValues(item);
      return {
        element: item,
        startLeft: itemValues.left,
        startTop: itemValues.top,
        startWidth: itemValues.width,
        startHeight: itemValues.height
      };
    })
    : [];

  dragState = {
    element: el,
    items: dragItems,
    pointerId: e.pointerId,
    startX: e.clientX,
    startY: e.clientY,
    startLeft: values.left,
    startTop: values.top,
    startWidth: values.width,
    startHeight: values.height,
    canvasWidth: canvasRect.width
  };

  const captureTarget = moveHandle || el;
  captureTarget.setPointerCapture(e.pointerId);
});

sitePage.addEventListener('pointermove', e => {
  if (!dragState) return;

  const el = dragState.element;
  const dxPercent = (e.clientX - dragState.startX) / dragState.canvasWidth * 100;
  const dyPx = e.clientY - dragState.startY;

  const allowOverflowMove = canElementOverflowDragV134(el);
  const rawLeft = allowOverflowMove
    ? (dragState.startLeft + dxPercent)
    : clamp(dragState.startLeft + dxPercent, 0, 100);
  const rawTop = allowOverflowMove
    ? (dragState.startTop + dyPx)
    : Math.max(0, dragState.startTop + dyPx);
  // v77：形狀也要跟圖片一樣顯示對齊輔助線與吸附效果
  const snapped = applyDragAlignmentSnap(el, rawLeft, rawTop);

  if (dragState.items && dragState.items.length > 1) {
    const deltaLeft = snapped.left - dragState.startLeft;
    const deltaTop = snapped.top - dragState.startTop;

    dragState.items.forEach(item => {
      const itemAllowOverflow = canElementOverflowDragV134(item.element);
      const itemNext = clampSelectSwitcherTemplatePositionV134(
        item.element,
        itemAllowOverflow ? (item.startLeft + deltaLeft) : clamp(item.startLeft + deltaLeft, 0, 100),
        itemAllowOverflow ? (item.startTop + deltaTop) : Math.max(0, item.startTop + deltaTop)
      );
      item.element.style.left = itemNext.left + '%';
      item.element.style.top = itemNext.top + 'px';

      if (item.element.dataset.type === 'select-switcher-control' || item.element.dataset.selectSwitcherControl === 'true') {
        item.element.style.width = item.startWidth + '%';
        item.element.style.height = item.startHeight + 'px';
      }
    });
  } else {
    el.style.left = snapped.left + '%';
    el.style.top = snapped.top + 'px';

    if (el.dataset.type === 'select-switcher-control' || el.dataset.selectSwitcherControl === 'true') {
      el.style.width = dragState.startWidth + '%';
      el.style.height = dragState.startHeight + 'px';
    }
  }

  refreshInspector();
});

sitePage.addEventListener('pointerup', e => {
  const droppedElement = dragState ? dragState.element : null;

  if (dragState) {
    try {
      e.target.releasePointerCapture(e.pointerId);
    } catch (err) {}
  }

  dragState = null;

  if (droppedElement) {
    moveElementIntoHoverSlideGroupIfNeeded(droppedElement);
  }

  hideAllAlignmentGuides();
});

sitePage.addEventListener('pointercancel', () => {
  dragState = null;
  hideAllAlignmentGuides();
});

// v96：多選 Canva 式縮放工具
function getMultiResizeItems(triggerEl) {
  const items = getActiveSelectedElements()
    .filter(item => item && item.isConnected && item.classList.contains('free-element') && !isElementLocked(item));

  if (items.length > 1 && items.includes(triggerEl) && getSharedElementContext(items)) return items;
  return [triggerEl].filter(Boolean);
}

function buildMultiResizeState(items, contextRect) {
  const data = items.map(el => getElementBoxData(el, contextRect));
  const bounds = getItemsBoundingBox(data);
  return {
    bounds,
    items: data.map(item => ({
      element: item.el,
      startLeftPx: item.leftPx,
      startTopPx: item.topPx,
      startWidthPx: item.width,
      startHeightPx: item.height
    }))
  };
}

function updateMultiResize(e) {
  if (!resizeState || resizeState.mode !== 'multi') return;

  const dir = resizeState.direction;
  const bounds = resizeState.groupBounds;
  const dx = e.clientX - resizeState.startX;
  const dy = e.clientY - resizeState.startY;
  const contextRect = resizeState.contextRect;
  const minW = 24;
  const minH = 24;

  let left = bounds.left;
  let top = bounds.top;
  let width = bounds.width;
  let height = bounds.height;

  if (dir.includes('e')) width = bounds.width + dx;
  if (dir.includes('w')) {
    left = bounds.left + dx;
    width = bounds.width - dx;
  }

  if (dir.includes('s')) height = bounds.height + dy;
  if (dir.includes('n')) {
    top = bounds.top + dy;
    height = bounds.height - dy;
  }

  width = Math.max(minW, width);
  height = Math.max(minH, height);

  const isCorner = ['nw', 'ne', 'se', 'sw'].includes(dir);
  if (isCorner || e.shiftKey) {
    const startAspect = Math.max(bounds.width, 1) / Math.max(bounds.height, 1);
    const scaleX = width / Math.max(bounds.width, 1);
    const scaleY = height / Math.max(bounds.height, 1);
    const scale = Math.abs(scaleX - 1) >= Math.abs(scaleY - 1) ? scaleX : scaleY;
    width = Math.max(minW, bounds.width * scale);
    height = Math.max(minH, width / startAspect);

    if (dir.includes('w')) left = bounds.right - width;
    else left = bounds.left;

    if (dir.includes('n')) top = bounds.bottom - height;
    else top = bounds.top;
  }

  if (left < 0) left = 0;
  if (top < 0) top = 0;
  if (left + width > contextRect.width) {
    if (dir.includes('w')) left = Math.max(0, contextRect.width - width);
    else width = Math.max(minW, contextRect.width - left);
  }

  const scaleX = width / Math.max(bounds.width, 1);
  const scaleY = height / Math.max(bounds.height, 1);

  resizeState.items.forEach(item => {
    const nextLeft = left + (item.startLeftPx - bounds.left) * scaleX;
    const nextWidth = item.startWidthPx * scaleX;

    let nextTop = top + (item.startTopPx - bounds.top) * scaleY;
    let nextHeight = item.startHeightPx * scaleY;

    // v97：線條多選縮放時只改變長度與位置，不把線條粗細 / hitbox 高度一起縮放。
    if (item.element?.dataset?.type === 'line') {
      const startCenterY = item.startTopPx + item.startHeightPx / 2;
      const nextCenterY = top + (startCenterY - bounds.top) * scaleY;
      nextHeight = item.startHeightPx;
      nextTop = nextCenterY - nextHeight / 2;
    }

    setElementBoxFromPixels(item.element, nextLeft, nextTop, nextWidth, nextHeight, contextRect);
    if (item.element?.dataset?.type === 'line') applyLineStyleToElement(item.element);
  });

  refreshInspector();
}

// 八方向縮放
sitePage.addEventListener('pointerdown', e => {
  const handle = e.target.closest('.resize-handle');
  if (!handle) return;

  const el = handle.closest('.free-element');
  if (!el) return;

  const resizeDirection = handle.dataset.resize;
  const isYoutubeResize = el.dataset.type === 'youtube';
  const isCornerResize = ['nw', 'ne', 'se', 'sw'].includes(resizeDirection);

  // v21：影片只能從四個角等比例縮放，不能拉上下左右邊自由變形
  if (isYoutubeResize && !isCornerResize) return;

  if (isElementLocked(el)) return;

  e.preventDefault();
  e.stopPropagation();
  saveHistorySnapshot();

  const keepMultiSelection = selectedElements.length > 1 && selectedElements.includes(el);
  if (!keepMultiSelection) selectElement(el);

  const canvas = getElementPositionContext(el);
  const canvasRect = canvas.getBoundingClientRect();
  const values = getElementValues(el);
  const resizeItems = getMultiResizeItems(el);

  if (resizeItems.length > 1) {
    const multiState = buildMultiResizeState(resizeItems, canvasRect);
    resizeState = {
      mode: 'multi',
      element: el,
      direction: handle.dataset.resize,
      pointerId: e.pointerId,
      startX: e.clientX,
      startY: e.clientY,
      context: canvas,
      contextRect: canvasRect,
      groupBounds: multiState.bounds,
      items: multiState.items,
      canvasWidth: canvasRect.width
    };
  } else {
    resizeState = {
      mode: 'single',
      element: el,
      direction: handle.dataset.resize,
      pointerId: e.pointerId,
      startX: e.clientX,
      startY: e.clientY,
      startLeft: values.left,
      startTop: values.top,
      startW: values.width,
      startH: values.height,
      startWidthPx: canvasRect.width * values.width / 100,
      aspectRatio: (canvasRect.width * values.width / 100) / Math.max(values.height, 1),
      canvasWidth: canvasRect.width
    };
  }

  handle.setPointerCapture(e.pointerId);
});

sitePage.addEventListener('pointermove', e => {
  if (!resizeState) return;

  if (resizeState.mode === 'multi') {
    updateMultiResize(e);
    return;
  }

  const el = resizeState.element;
  const dir = resizeState.direction;
  const dxPercent = (e.clientX - resizeState.startX) / resizeState.canvasWidth * 100;
  const dyPx = e.clientY - resizeState.startY;

  let left = resizeState.startLeft;
  let top = resizeState.startTop;
  let width = resizeState.startW;
  let height = resizeState.startH;

  if (dir.includes('e')) width = resizeState.startW + dxPercent;
  if (dir.includes('w')) {
    left = resizeState.startLeft + dxPercent;
    width = resizeState.startW - dxPercent;
  }

  if (dir.includes('s')) height = resizeState.startH + dyPx;
  if (dir.includes('n')) {
    top = resizeState.startTop + dyPx;
    height = resizeState.startH - dyPx;
  }

  const isLine = el.dataset.type === 'line';
  const minW = isLine ? 1 : 3;
  const minH = 24;

  if (isLine) {
    // v97：線條縮放時保持粗細一致。縮放把手只改變線條長度，不改變線條本身高度。
    top = resizeState.startTop;
    height = resizeState.startH;
  }

  if (width < minW) {
    if (dir.includes('w')) left = resizeState.startLeft + resizeState.startW - minW;
    width = minW;
  }

  if (height < minH) {
    if (dir.includes('n')) top = resizeState.startTop + resizeState.startH - minH;
    height = minH;
  }

  if (left < 0) {
    width += left;
    left = 0;
  }

  if (left + width > 100) {
    width = 100 - left;
  }

  if (top < 0) {
    height += top;
    top = 0;
  }

  // v25：圖片/形狀四角按住 Shift 等比例縮放；影片四角永遠等比例縮放
  const isImage = el.dataset.type === 'image';
  const isYoutube = el.dataset.type === 'youtube';
  const isShape = el.dataset.type === 'shape';
  const isCorner = ['nw', 'ne', 'se', 'sw'].includes(dir);

  if ((isCorner && e.shiftKey) || (isYoutube && isCorner)) {
    const startLeftPx = resizeState.startLeft / 100 * resizeState.canvasWidth;
    const startRightPx = startLeftPx + resizeState.startWidthPx;
    const startTopPx = resizeState.startTop;
    const startBottomPx = startTopPx + resizeState.startH;

    let widthPx = width / 100 * resizeState.canvasWidth;
    let heightPx = height;

    const widthDelta = Math.abs(widthPx - resizeState.startWidthPx);
    const heightDelta = Math.abs(heightPx - resizeState.startH);

    if (widthDelta >= heightDelta) {
      heightPx = widthPx / resizeState.aspectRatio;
    } else {
      widthPx = heightPx * resizeState.aspectRatio;
    }

    widthPx = Math.max(24, widthPx);
    heightPx = Math.max(24, heightPx);

    if (dir.includes('w')) {
      left = (startRightPx - widthPx) / resizeState.canvasWidth * 100;
    }

    if (dir.includes('e')) {
      left = resizeState.startLeft;
    }

    if (dir.includes('n')) {
      top = startBottomPx - heightPx;
    }

    if (dir.includes('s')) {
      top = resizeState.startTop;
    }

    if (left < 0) {
      left = 0;
    }

    if (top < 0) {
      top = 0;
    }

    width = widthPx / resizeState.canvasWidth * 100;
    height = heightPx;

    if (left + width > 100) {
      width = 100 - left;
      height = (width / 100 * resizeState.canvasWidth) / resizeState.aspectRatio;
    }
  }

  el.style.left = left + '%';
  el.style.top = top + 'px';
  el.style.width = width + '%';
  el.style.height = height + 'px';

  if (el.dataset.type === 'line') {
    applyLineStyleToElement(el);
  }

  if (el.dataset.type === 'youtube') {
    selectedElement = el;
    selectedElement.dataset.youtubeAspectRatio = selectedElement.dataset.youtubeAspectRatio || '1.7777777778';
    syncYoutubeWidthControls();
  }

  refreshInspector();
});

sitePage.addEventListener('pointerup', () => {
  resizeState = null;
});

sitePage.addEventListener('pointercancel', () => {
  resizeState = null;
});

function updateBlockStyleFromManualInput() {
  if (!selectedBlock || selectedElement) return;

  const blockHeight = parseInt(document.getElementById('blockHeightPx').value) || 360;
  const paddingY = parseInt(document.getElementById('blockPaddingYPx').value) || 0;
  const paddingX = parseInt(document.getElementById('blockPaddingXPx').value) || 0;
  const radius = parseInt(document.getElementById('blockRadiusPx').value) || 0;

  setValue('blockHeight', blockHeight);
  setValue('blockPaddingY', paddingY);
  setValue('blockPaddingX', paddingX);
  setValue('blockRadius', radius);

  const canvas = selectedBlock.querySelector('.block-canvas');

  selectedBlock.style.paddingTop = paddingY + 'px';
  selectedBlock.style.paddingBottom = paddingY + 'px';
  selectedBlock.style.paddingLeft = paddingX + 'px';
  selectedBlock.style.paddingRight = paddingX + 'px';
  selectedBlock.style.borderRadius = radius + 'px';
  selectedBlock.style.minHeight = (blockHeight + paddingY * 2) + 'px';
  canvas.style.minHeight = blockHeight + 'px';
}


