// v15：本機圖片上傳
document.getElementById('imageUploadInput').addEventListener('change', e => {
  if (!selectedElement || selectedElement.dataset.type !== 'image') return;

  const img = selectedElement.querySelector('img.editable-image');
  if (!img) return;

  const file = e.target.files && e.target.files[0];
  if (!file) return;

  if (!file.type.startsWith('image/')) {
    alert('請選擇圖片檔案');
    e.target.value = '';
    return;
  }

  const reader = new FileReader();

  reader.onload = event => {
    img.src = event.target.result;
    attachImageLoadHandler(img);
    document.getElementById('imageUrlInput').value = '';

    if (selectedElement.dataset.originalScaleEnabled !== 'true') {
      selectedElement.dataset.originalScaleEnabled = 'true';
      selectedElement.dataset.originalScale = selectedElement.dataset.originalScale || '100';
      document.getElementById('imageOriginalScaleToggle').checked = true;
      setImageOriginalScaleControlsEnabled(true);
    }
  };

  reader.readAsDataURL(file);
});

