/* v81：導覽列下拉標題離開標題、移到選單前不會立刻收起 */
let navDropdownCloseTimer = null;

sitePage.addEventListener('mouseover', event => {
  const root = event.target.closest('.nav-dropdown');
  if (!root) return;

  window.clearTimeout(navDropdownCloseTimer);
  root.classList.add('menu-open');
}, true);

sitePage.addEventListener('mouseout', event => {
  const root = event.target.closest('.nav-dropdown');
  if (!root) return;

  const next = event.relatedTarget;
  if (next && root.contains(next)) return;

  window.clearTimeout(navDropdownCloseTimer);
  navDropdownCloseTimer = window.setTimeout(() => {
    root.classList.remove('menu-open');
  }, 280);
}, true);


