// 上方功能：v39 側邊欄隱藏 / 顯示
function syncSidebarToggleButtons() {
  const leftHidden = document.body.classList.contains('hide-left-panel');
  const rightHidden = document.body.classList.contains('hide-right-panel');

  document.getElementById('toggleLeftSidebarBtn').innerHTML = leftHidden
    ? '<i class="bi bi-layout-sidebar-inset"></i> 顯示左側欄'
    : '<i class="bi bi-layout-sidebar-inset"></i> 隱藏左側欄';

  document.getElementById('toggleRightSidebarBtn').innerHTML = rightHidden
    ? '<i class="bi bi-layout-sidebar-inset-reverse"></i> 顯示右側欄'
    : '<i class="bi bi-layout-sidebar-inset-reverse"></i> 隱藏右側欄';
}

document.getElementById('toggleLeftSidebarBtn').addEventListener('click', () => {
  document.body.classList.toggle('hide-left-panel');
  document.body.classList.remove('left-sidebar-collapsed');
  document.documentElement.style.setProperty('--sidebar-width', '245px');
  syncSidebarToggleButtons();
});

document.getElementById('toggleRightSidebarBtn').addEventListener('click', () => {
  document.body.classList.toggle('hide-right-panel');
  document.body.classList.remove('right-sidebar-collapsed');
  document.documentElement.style.setProperty('--inspector-width', '290px');
  syncSidebarToggleButtons();
});

syncSidebarToggleButtons();

document.getElementById('previewBtn').addEventListener('click', () => {
  captureCurrentPage();
  clearEditorSelectionForPreview();
  hideAllAlignmentGuides();
  initSelectSwitchers(sitePage);
  initSideDrawerRuntime(sitePage);
  initHoverSlideGroups(sitePage);
  initAccordionDropdowns(sitePage);
  syncAllCarouselPeekLayouts(sitePage);
  clearEditorSelectionForPreview();
  initBaseSlideAnimations(sitePage);
  initCardCarouselRuntime(sitePage, true);

  document.querySelectorAll('.free-element[data-type="youtube"]').forEach(el => {
    const iframe = el.querySelector('iframe.editable-youtube');
    const placeholder = el.querySelector('.youtube-placeholder');

    if (iframe && iframe.getAttribute('src')) {
      iframe.classList.remove('d-none');
      iframe.style.pointerEvents = 'auto';
      iframe.setAttribute('allowfullscreen', '');
      iframe.setAttribute('allow', 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share');
      iframe.setAttribute('referrerpolicy', 'strict-origin-when-cross-origin');
      iframe.setAttribute('loading', 'lazy');
      if (placeholder) placeholder.classList.add('d-none');

      // 重新指定一次 src，避免從編輯模式切到預覽時 iframe 還停在不可互動狀態
      const src = iframe.getAttribute('src');
      iframe.setAttribute('src', src);
    }
  });

  document.querySelectorAll('.html-zone').forEach(zone => {
    const hasVisibleBlock = !!zone.querySelector(':scope > .html-block');
    zone.classList.toggle('preview-empty-zone', !hasVisibleBlock);
  });

  const canvas = document.querySelector('.canvas-area');
  if (canvas) {
    canvas.style.removeProperty('--preview-bottom-extra-v95');
    canvas.style.removeProperty('min-height');
  }

  document.body.classList.add('preview-mode');
});

document.getElementById('exitPreviewBtn').addEventListener('click', () => {
  document.body.classList.remove('preview-mode');
  document.querySelectorAll('.html-zone.preview-empty-zone').forEach(zone => zone.classList.remove('preview-empty-zone'));
  clearCarouselAutoTimers();
  initSelectSwitchers(sitePage);

  document.querySelectorAll('.free-element[data-type="youtube"] iframe.editable-youtube').forEach(iframe => {
    iframe.style.pointerEvents = '';
  });
});

