/* v49：包裝常用修改動作，讓 Ctrl+Z 可返回上一步 */
function wrapHistoryAction(name) {
  if (typeof window[name] !== 'function') return;

  const original = window[name];

  window[name] = function (...args) {
    saveHistorySnapshot();
    return original.apply(this, args);
  };

  try {
    eval(name + ' = window[name];');
  } catch (error) {}
}

