document.addEventListener('click', function (event) {
  var imgEl = event.target.closest('.free-element[data-type="image"][data-click-swap-enabled="true"]');
  if (!imgEl) return;

  var img = imgEl.querySelector('img.editable-image');
  var swap = imgEl.getAttribute('data-swap-src');

  if (!img || !swap) return;

  event.preventDefault();
  var current = img.getAttribute('src');
  img.setAttribute('src', swap);
  imgEl.setAttribute('data-swap-src', current);
}, true);


