document.addEventListener('keydown', e => {
  if (isTypingNow()) return;

  const key = e.key.toLowerCase();

  if ((e.ctrlKey || e.metaKey) && key === 'p') {
    e.preventDefault();
    openManualSaveHistoryPanel();
    return;
  }

  if ((e.ctrlKey || e.metaKey) && key === 'z') {
    e.preventDefault();
    undoLastAction();
    return;
  }

  if (e.key === 'Delete' || e.key === 'Backspace') {
    e.preventDefault();
    deleteSelected();
  }

  // v40：Ctrl+C 複製、Ctrl+V 貼上，貼上位置維持原位
  if ((e.ctrlKey || e.metaKey) && key === 'c') {
    e.preventDefault();
    copySelected();
  }

  if ((e.ctrlKey || e.metaKey) && key === 'v') {
    e.preventDefault();
    pasteCopied();
  }

  if ((e.ctrlKey || e.metaKey) && key === 'd') {
    e.preventDefault();
    cloneSelected();
  }

  if (selectedElement && ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
    e.preventDefault();
    saveHistorySnapshot();

    const stepPx = e.shiftKey ? 10 : 1;
    const context = getElementPositionContext(selectedElement);
    const canvasWidth = context.getBoundingClientRect().width || 1;
    const values = getElementValues(selectedElement);

    if (e.key === 'ArrowUp') selectedElement.style.top = Math.max(0, values.top - stepPx) + 'px';
    if (e.key === 'ArrowDown') selectedElement.style.top = Math.max(0, values.top + stepPx) + 'px';
    if (e.key === 'ArrowLeft') selectedElement.style.left = Math.max(0, values.left - (stepPx / canvasWidth * 100)) + '%';
    if (e.key === 'ArrowRight') selectedElement.style.left = Math.min(100, values.left + (stepPx / canvasWidth * 100)) + '%';

    refreshInspector();
  }

  if (e.key === 'Escape') {
    closeManualSaveHistoryPanel();
    selectBlock(null);
  }
});

