/* v57：右側設定卡片收合 */
function initCollapsibleSettingCards() {
  document.querySelectorAll('.editor-inspector .setting-card').forEach((card, index) => {
    const title = card.querySelector(':scope > .setting-title');
    if (!title || card.dataset.collapsibleReady === 'true') return;

    const content = document.createElement('div');
    content.className = 'setting-card-content';

    Array.from(card.children).forEach(child => {
      if (child !== title) content.appendChild(child);
    });

    card.appendChild(content);
    card.dataset.collapsibleReady = 'true';

    if (card.dataset.noCollapse === 'true') {
      card.classList.remove('collapsed');
      return;
    }

    if (index > 0) {
      card.classList.add('collapsed');
    }

    title.addEventListener('click', event => {
      if (event.target.closest('button, input, select, textarea, label, a')) return;
      card.classList.toggle('collapsed');
    });
  });
}

function openSettingCard(id) {
  const card = document.getElementById(id);
  if (card) card.classList.remove('collapsed');
}

/* v57：側邊欄模板 icon 滑出 */
